import React, { useEffect, useRef, useState } from 'react';
import { Link, NavLink, Outlet } from 'react-router-dom';
import { useNavigate } from 'react-router-dom';
import supportService from '../services/supportService';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';

export default function CustomerDashboardLayout() {
    const { user, logout, logoutLoading } = useAuth();
    const { cartItems, cartCount, cartSummary } = useCart();
    const [menuOpen, setMenuOpen] = useState(false);
    const [cartOpen, setCartOpen] = useState(false);
    const [notificationsOpen, setNotificationsOpen] = useState(false);
    const [notificationItems, setNotificationItems] = useState([]);
    const [loadingNotifications, setLoadingNotifications] = useState(false);
    const [readReplyIds, setReadReplyIds] = useState([]);
    const menuRef = useRef(null);
    const cartRef = useRef(null);
    const notificationsRef = useRef(null);
    const autoCloseCartTimerRef = useRef<number | null>(null);
    const navigate = useNavigate();

    const readStorageKey = `carvex-read-admin-replies-${user?.id || 'guest'}`;

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (menuRef.current && !menuRef.current.contains(event.target)) {
                setMenuOpen(false);
            }

            if (cartRef.current && !cartRef.current.contains(event.target)) {
                setCartOpen(false);
            }

            if (notificationsRef.current && !notificationsRef.current.contains(event.target)) {
                setNotificationsOpen(false);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        const handleCartItemAdded = () => {
            setCartOpen(true);

            if (autoCloseCartTimerRef.current !== null) {
                window.clearTimeout(autoCloseCartTimerRef.current);
            }

            autoCloseCartTimerRef.current = window.setTimeout(() => {
                setCartOpen(false);
                autoCloseCartTimerRef.current = null;
            }, 1800);
        };

        window.addEventListener('carvex:cart-item-added', handleCartItemAdded);
        return () => {
            window.removeEventListener('carvex:cart-item-added', handleCartItemAdded);
            if (autoCloseCartTimerRef.current !== null) {
                window.clearTimeout(autoCloseCartTimerRef.current);
                autoCloseCartTimerRef.current = null;
            }
        };
    }, []);

    useEffect(() => {
        try {
            const raw = window.localStorage.getItem(readStorageKey);
            const parsed = raw ? JSON.parse(raw) : [];
            setReadReplyIds(Array.isArray(parsed) ? parsed : []);
        } catch {
            setReadReplyIds([]);
        }
    }, [readStorageKey]);

    useEffect(() => {
        try {
            window.localStorage.setItem(readStorageKey, JSON.stringify(readReplyIds));
        } catch {
            // Ignore storage quota/read-only failures.
        }
    }, [readReplyIds, readStorageKey]);

    useEffect(() => {
        let active = true;

        const loadNotifications = async () => {
            try {
                setLoadingNotifications(true);
                const res = await supportService.getMyConcerns();
                if (!active) {
                    return;
                }

                const concerns = Array.isArray(res?.data?.data?.data || res?.data?.data)
                    ? (res?.data?.data?.data || res?.data?.data)
                    : [];

                const replies = concerns
                    .filter((concern) => String(concern?.admin_reply || '').trim().length > 0)
                    .sort((a, b) => new Date(b.replied_at || b.updated_at || b.created_at).getTime() - new Date(a.replied_at || a.updated_at || a.created_at).getTime());

                setNotificationItems(replies);
            } catch {
                if (active) {
                    setNotificationItems([]);
                }
            } finally {
                if (active) {
                    setLoadingNotifications(false);
                }
            }
        };

        loadNotifications();
        const intervalId = window.setInterval(loadNotifications, 30000);

        return () => {
            active = false;
            window.clearInterval(intervalId);
        };
    }, []);

    const unreadCount = notificationItems.filter((item) => !readReplyIds.includes(item.id)).length;

    const markNotificationRead = (id) => {
        setReadReplyIds((prev) => (prev.includes(id) ? prev : [...prev, id]));
    };

    const markAllRead = () => {
        setReadReplyIds(notificationItems.map((item) => item.id));
    };

    const formatNotificationTime = (value) => {
        if (!value) {
            return 'Just now';
        }

        return new Date(value).toLocaleString();
    };

    const currency = (value) => new Intl.NumberFormat('en-PH', {
        style: 'currency',
        currency: 'PHP',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(Number(value || 0));

    const getCartImage = (item) => {
        const images = item?.product?.images;

        if (Array.isArray(images) && images.length > 0) {
            return images[0];
        }

        if (typeof images === 'string') {
            try {
                const parsed = JSON.parse(images);
                if (Array.isArray(parsed) && parsed.length > 0) {
                    return parsed[0];
                }
            } catch {
                return '/images/carvex.png';
            }
        }

        return '/images/carvex.png';
    };

    const cartSubtotal = Number(cartSummary?.subtotal || 0);
    const cartShipping = Number(cartSummary?.shipping || 0);
    const cartTotal = Number(cartSummary?.total || 0);
    const cartPreviewItems = cartItems.slice(0, 4);

    const initials = (user?.name || 'U')
        .split(' ')
        .filter(Boolean)
        .slice(0, 2)
        .map((part) => part[0]?.toUpperCase())
        .join('') || 'U';

    const handleLogout = async () => {
        if (logoutLoading) {
            return;
        }

        await logout();
        setMenuOpen(false);
        navigate('/');
    };

    return (
        <div className="customer-panel-shell">
            <header className="customer-panel-topbar">
                <Link to="/dashboard" className="customer-panel-brand">
                    <span className="customer-panel-brand-mark" aria-hidden="true">
                        CV
                    </span>
                    <span className="customer-panel-brand-details">
                        <span className="customer-panel-brand-name">CarVex</span>
                        <span className="customer-panel-brand-tagline">PREMIUM AUTO PARTS</span>
                    </span>
                </Link>

                <nav className="customer-panel-nav">
                    <NavLink to="/dashboard" className={({ isActive }) => `customer-panel-nav-link ${isActive ? 'active' : ''}`}>Home</NavLink>
                    <NavLink end to="/dashboard" className={({ isActive }) => `customer-panel-nav-link ${isActive ? 'active' : ''}`}>Dashboard</NavLink>
                    <NavLink to="/dashboard/products" className={({ isActive }) => `customer-panel-nav-link ${isActive ? 'active' : ''}`}>Products</NavLink>
                    <NavLink to="/dashboard/orders" className={({ isActive }) => `customer-panel-nav-link ${isActive ? 'active' : ''}`}>
                        My Orders
                    </NavLink>
                </nav>

                <div className="customer-panel-actions">
                    <div className="customer-cart-menu" ref={cartRef}>
                        <button
                            type="button"
                            className="customer-panel-icon-link"
                            aria-label="Cart"
                            aria-haspopup="menu"
                            aria-expanded={cartOpen}
                            title={`Cart${cartCount > 0 ? ` (${cartCount})` : ''}`}
                            onClick={() => setCartOpen((prev) => !prev)}
                        >
                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
                                <path d="M3 13h2l.8-4.2A2 2 0 0 1 7.77 7h8.46a2 2 0 0 1 1.97 1.62L19 13h2" />
                                <path d="M5 13l1 5h12l1-5" />
                                <circle cx="8" cy="19" r="1.5" />
                                <circle cx="17" cy="19" r="1.5" />
                            </svg>
                            {cartCount > 0 && <span className="customer-panel-cart-count">{cartCount}</span>}
                        </button>

                        {cartOpen && (
                            <div className="customer-cart-dropdown" role="menu" aria-label="Cart preview">
                                <div className="customer-cart-dropdown__header">
                                    <strong>Your Cart</strong>
                                    <span>{cartCount} item{cartCount === 1 ? '' : 's'}</span>
                                </div>

                                <div className="customer-cart-dropdown__list">
                                    {cartPreviewItems.length === 0 ? (
                                        <p className="customer-cart-empty">Your cart is empty.</p>
                                    ) : (
                                        cartPreviewItems.map((item) => (
                                            <Link
                                                key={item.id}
                                                to="/dashboard/cart"
                                                className="customer-cart-dropdown-item"
                                                onClick={() => setCartOpen(false)}
                                            >
                                                <img src={getCartImage(item)} alt={item.product?.name || 'Cart item'} />
                                                <div className="customer-cart-dropdown-item__body">
                                                    <strong>{item.product?.name || 'Cart item'}</strong>
                                                    <span>{item.quantity} x {currency(item.product?.price)}</span>
                                                </div>
                                            </Link>
                                        ))
                                    )}
                                </div>

                                <div className="customer-cart-dropdown__summary">
                                    <div>
                                        <span>Subtotal</span>
                                        <strong>{currency(cartSubtotal)}</strong>
                                    </div>
                                    <div>
                                        <span>Shipping</span>
                                        <strong>{currency(cartShipping)}</strong>
                                    </div>
                                    <div>
                                        <span>Total</span>
                                        <strong>{currency(cartTotal)}</strong>
                                    </div>
                                </div>

                                <div className="customer-cart-dropdown__footer">
                                    <Link to="/dashboard/cart" onClick={() => setCartOpen(false)}>View Cart</Link>
                                    <Link to="/dashboard/checkout" onClick={() => setCartOpen(false)}>Checkout</Link>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="customer-notification-menu" ref={notificationsRef}>
                        <button
                            type="button"
                            className="customer-panel-icon-link"
                            aria-label="Order Notifications"
                            aria-haspopup="menu"
                            aria-expanded={notificationsOpen}
                            onClick={() => setNotificationsOpen((prev) => !prev)}
                        >
                            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
                                <path d="M15 17h5l-1.4-1.4a2 2 0 0 1-.6-1.4V11a6 6 0 1 0-12 0v3.2a2 2 0 0 1-.6 1.4L4 17h5" />
                                <path d="M9 17a3 3 0 0 0 6 0" />
                            </svg>
                            {unreadCount > 0 && <span className="customer-panel-cart-count">{unreadCount}</span>}
                        </button>

                        {notificationsOpen && (
                            <div className="customer-notification-dropdown" role="menu">
                                <div className="customer-notification-dropdown__header">
                                    <strong>Notifications</strong>
                                    {unreadCount > 0 && <span>{unreadCount} new</span>}
                                </div>

                                <div className="customer-notification-dropdown__list">
                                    {loadingNotifications ? (
                                        <p className="customer-notification-empty">Loading notifications...</p>
                                    ) : notificationItems.length === 0 ? (
                                        <p className="customer-notification-empty">No admin messages yet.</p>
                                    ) : (
                                        notificationItems.slice(0, 6).map((item) => (
                                            <button
                                                type="button"
                                                key={item.id}
                                                className={`customer-notification-item ${readReplyIds.includes(item.id) ? '' : 'is-unread'}`}
                                                onClick={() => markNotificationRead(item.id)}
                                            >
                                                <div className="customer-notification-item__meta">
                                                    <strong>{item.subject || 'Order update'}</strong>
                                                    {!readReplyIds.includes(item.id) && <span className="customer-notification-dot" aria-hidden="true" />}
                                                </div>
                                                <p>{item.admin_reply}</p>
                                                <time>{formatNotificationTime(item.replied_at || item.updated_at || item.created_at)}</time>
                                            </button>
                                        ))
                                    )}
                                </div>

                                <div className="customer-notification-dropdown__footer">
                                    <button type="button" onClick={() => setNotificationsOpen(false)}>Close</button>
                                    <button type="button" onClick={markAllRead}>Mark all read</button>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="customer-profile-menu" ref={menuRef}>
                        <button
                            type="button"
                            className="customer-profile-trigger"
                            onClick={() => setMenuOpen((prev) => !prev)}
                            aria-haspopup="menu"
                            aria-expanded={menuOpen}
                        >
                            <span className="customer-profile-avatar" aria-hidden="true">
                                {user?.avatar_url ? <img src={user.avatar_url} alt="Profile" /> : initials}
                            </span>
                        </button>

                        {menuOpen && (
                            <div className="customer-profile-dropdown" role="menu">
                                <Link
                                    to="/dashboard/profile"
                                    className="customer-profile-dropdown-link"
                                    onClick={() => setMenuOpen(false)}
                                >
                                    Profile
                                </Link>
                                <Link
                                    to="/dashboard/settings"
                                    className="customer-profile-dropdown-link"
                                    onClick={() => setMenuOpen(false)}
                                >
                                    Settings
                                </Link>
                                <button
                                    type="button"
                                    className="customer-profile-dropdown-link customer-profile-dropdown-link--danger"
                                    onClick={handleLogout}
                                    disabled={logoutLoading}
                                >
                                    Logout
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            </header>

            <main className="customer-panel-content">
                <Outlet />
            </main>
        </div>
    );
}
