import { createClient } from '@supabase/supabase-js';

const supabaseUrl = String(process.env.MIX_SUPABASE_URL || '').trim();
const supabaseAnonKey = String(process.env.MIX_SUPABASE_ANON_KEY || '').trim();

if (!supabaseUrl || !supabaseAnonKey) {
	throw new Error('Missing Supabase config. Set MIX_SUPABASE_URL and MIX_SUPABASE_ANON_KEY in .env.');
}

export const supabase = createClient(supabaseUrl, supabaseAnonKey);
