import React, { useEffect, useRef, useState } from 'react';
import { Link, NavLink, Outlet, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import adminService from '../services/adminService';
import { preloadAdminRoute, preloadAllAdminRoutes } from '../utils/adminRoutePreload';

const SIDEBAR_REFRESH_MS = 30000;
const SIDEBAR_CACHE_KEY = 'admin_sidebar_counts_v2';

const readCachedSidebarCounts = () => {
    try {
        const raw = localStorage.getItem(SIDEBAR_CACHE_KEY);
        if (!raw) {
            return null;
        }

        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') {
            return null;
        }

        return {
            products: Number(parsed.products || 0),
            orders: Number(parsed.orders || 0),
            users: Number(parsed.users || 0),
            newConcerns: Number(parsed.newConcerns || 0),
        };
    } catch {
        return null;
    }
};

const extractCollection = (response) => {
    const payload = response?.data?.data;

    if (Array.isArray(payload?.data)) {
        return payload.data;
    }

    if (Array.isArray(payload)) {
        return payload;
    }

    return [];
};

const extractTotal = (response) => {
    const payload = response?.data?.data;
    const total = Number(payload?.total);
    if (Number.isFinite(total) && total >= 0) {
        return total;
    }

    return extractCollection(response).length;
};

export default function AdminLayout() {
    const location = useLocation();
    const navigate = useNavigate();
    const { logout, logoutLoading } = useAuth();
    const [menuOpen, setMenuOpen] = useState(false);
    const [sidebarCounts, setSidebarCounts] = useState(() => readCachedSidebarCounts() || {
        products: 0,
        orders: 0,
        users: 0,
        newConcerns: 0,
    });
    const menuRef = useRef(null);
    const sidebarRequestIdRef = useRef(0);

    const titleMap = {
        '/admin/dashboard': 'Dashboard',
        '/admin/products': 'Products',
        '/admin/users': 'Users',
        '/admin/customer-service': 'Customer Service',
        '/admin/concerns': 'Customer Service',
        '/admin/analytics': 'Analytics',
        '/admin/account': 'Account',
    };

    const title = titleMap[location.pathname] || 'Dashboard';

    const navItems = [
        {
            to: '/admin/dashboard',
            label: 'Dashboard',
            icon: (
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                    <rect x="3" y="3" width="7" height="7" rx="1.5" />
                    <rect x="14" y="3" width="7" height="7" rx="1.5" />
                    <rect x="3" y="14" width="7" height="7" rx="1.5" />
                    <rect x="14" y="14" width="7" height="7" rx="1.5" />
                </svg>
            ),
        },
        {
            to: '/admin/products',
            label: 'Inventory',
            badge: sidebarCounts.products,
            badgeClass: 'count',
            icon: (
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                    <path d="M3 7.5 12 3l9 4.5-9 4.5L3 7.5Z" />
                    <path d="M3 16.5 12 21l9-4.5" />
                    <path d="M3 12 12 16.5 21 12" />
                </svg>
            ),
        },
        {
            to: '/admin/users',
            label: 'Users',
            badge: sidebarCounts.users,
            badgeClass: 'count',
            icon: (
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                    <circle cx="9" cy="8" r="3" />
                    <circle cx="17" cy="9" r="2.5" />
                    <path d="M4 19c0-2.8 2.2-5 5-5s5 2.2 5 5" />
                    <path d="M14 19c.2-2 1.8-3.5 3.9-3.5 1.3 0 2.4.6 3.1 1.5" />
                </svg>
            ),
        },
        {
            to: '/admin/customer-service',
            label: 'Customer Service',
            badge: sidebarCounts.newConcerns > 0 ? `New ${sidebarCounts.newConcerns}` : '',
            badgeClass: sidebarCounts.newConcerns > 0 ? 'new' : '',
            icon: (
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                    <path d="M12 3a9 9 0 1 0 9 9c0-4.97-4.03-9-9-9Z" />
                    <path d="M12 8v5" />
                    <circle cx="12" cy="16.5" r="1" />
                </svg>
            ),
        },
        {
            to: '/admin/analytics',
            label: 'Analytics',
            icon: (
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                    <path d="M4 20h16" />
                    <rect x="6" y="11" width="2.5" height="7" rx="1" />
                    <rect x="10.8" y="8" width="2.5" height="10" rx="1" />
                    <rect x="15.6" y="5" width="2.5" height="13" rx="1" />
                </svg>
            ),
        },
        {
            to: '/admin/account',
            label: 'Account',
            icon: (
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" aria-hidden="true">
                    <circle cx="12" cy="8" r="3.2" />
                    <path d="M5 20c0-3.5 3-6.2 7-6.2s7 2.7 7 6.2" />
                </svg>
            ),
        },
    ];

    const loadSidebarCounts = async () => {
        sidebarRequestIdRef.current += 1;
        const requestId = sidebarRequestIdRef.current;

        try {
            const [productsResult, usersResult, concernsResult] = await Promise.allSettled([
                adminService.getProducts({
                    timeout: 3000,
                    params: {
                        count_only: true,
                    },
                }),
                adminService.getUsers({
                    timeout: 3000,
                    params: {
                        count_only: true,
                    },
                }),
                adminService.getCustomerConcerns({ status: 'pending' }, { timeout: 2500 }),
            ]);

            if (sidebarRequestIdRef.current !== requestId) {
                return;
            }

            const products = productsResult.status === 'fulfilled' ? extractTotal(productsResult.value) : null;
            const users = usersResult.status === 'fulfilled' ? extractTotal(usersResult.value) : null;
            let newConcerns = null;

            if (concernsResult.status === 'fulfilled') {
                const concernData = concernsResult.value?.data?.data;
                const concernRows = extractCollection(concernsResult.value);
                const concernTotal = Number(concernData?.total || 0);
                newConcerns = concernTotal > 0 ? concernTotal : concernRows.length;
            }

            setSidebarCounts((prev) => ({
                products: Number.isFinite(products) ? products : prev.products,
                orders: 0,
                users: Number.isFinite(users) ? users : prev.users,
                newConcerns: Number.isFinite(newConcerns) ? newConcerns : prev.newConcerns,
            }));
        } catch {
            // Keep current badges if background refresh fails.
        }
    };

    useEffect(() => {
        preloadAllAdminRoutes();

        localStorage.setItem(SIDEBAR_CACHE_KEY, JSON.stringify(sidebarCounts));
    }, [sidebarCounts]);

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (menuRef.current && !menuRef.current.contains(event.target)) {
                setMenuOpen(false);
            }
        };

        // Load sidebar counts asynchronously without blocking render
        // Use cached data immediately, refresh in background
        if (Object.values(sidebarCounts).some(val => val > 0)) {
            // Have cached data, refresh silently after a short delay
            setTimeout(() => loadSidebarCounts(), 1500);
        } else {
            // No cached data, try to load but non-blocking
            setTimeout(() => loadSidebarCounts(), 300);
        }

        const intervalId = window.setInterval(loadSidebarCounts, SIDEBAR_REFRESH_MS);

        const handleVisibility = () => {
            if (document.visibilityState === 'visible') {
                // Refresh when tab becomes visible
                setTimeout(() => loadSidebarCounts(), 300);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        document.addEventListener('visibilitychange', handleVisibility);

        return () => {
            sidebarRequestIdRef.current += 1;
            window.clearInterval(intervalId);
            document.removeEventListener('mousedown', handleClickOutside);
            document.removeEventListener('visibilitychange', handleVisibility);
        };
    }, []);

    const handleLogout = async () => {
        if (logoutLoading) {
            return;
        }

        if (!window.confirm('Are you sure you want to logout from admin?')) {
            return;
        }

        try {
            await logout();
            navigate('/');
        } catch {
            navigate('/');
        }
    };

    return (
        <div className="admin-shell">
            <aside className="admin-sidebar">
                <div className="admin-brand">CarVex</div>
                <nav className="admin-sidebar-nav">
                    {navItems.map((item) => (
                        <NavLink
                            key={`${item.to}-${item.label}`}
                            to={item.to}
                            className={({ isActive }) => `admin-side-link ${isActive ? 'active' : ''}`}
                            onMouseEnter={() => preloadAdminRoute(item.to)}
                            onFocus={() => preloadAdminRoute(item.to)}
                        >
                            <span className="icon">{item.icon}</span>
                            <span className="admin-side-link__label">{item.label}</span>
                            {item.badge !== undefined && item.badge !== '' && (
                                <span className={`admin-side-badge ${item.badgeClass ? `admin-side-badge--${item.badgeClass}` : ''}`}>
                                    {item.badge}
                                </span>
                            )}
                        </NavLink>
                    ))}
                </nav>
            </aside>

            <main className="admin-dashboard-main">
                <header className="admin-dashboard-topbar">
                    <h1>{title}</h1>
                    {logoutLoading && (
                        <div className="admin-logout-status" role="status" aria-live="polite" aria-atomic="true">
                            <span className="admin-logout-spinner" aria-hidden="true" />
                            Please wait...
                        </div>
                    )}
                    <div className="admin-profile-menu" ref={menuRef}>
                        <button
                            type="button"
                            className="admin-user-chip admin-user-chip--button"
                            onClick={() => setMenuOpen((prev) => !prev)}
                        >
                            <div className="admin-user-meta">
                                <strong>Admin User</strong>
                                <span>admin@carvex.com</span>
                            </div>
                            <div className="admin-user-avatar">A</div>
                        </button>

                        {menuOpen && (
                            <div className="admin-profile-dropdown">
                                <Link to="/admin/account" className="admin-profile-dropdown-link" onClick={() => setMenuOpen(false)}>
                                    Settings
                                </Link>
                                <button
                                    type="button"
                                    className="admin-profile-dropdown-link admin-profile-dropdown-link--danger"
                                    onClick={handleLogout}
                                    disabled={logoutLoading}
                                    aria-busy={logoutLoading}
                                >
                                    Logout
                                </button>
                            </div>
                        )}
                    </div>
                </header>

                <Outlet />
            </main>
        </div>
    );
}