import api from './api';
import { AxiosRequestConfig, AxiosPromise } from 'axios';

interface CartItemData {
    product_id: number;
    quantity: number;
}

interface CartUpdateData {
    quantity: number;
}

const withCartConfig = (config?: AxiosRequestConfig, extras: Record<string, unknown> = {}): AxiosRequestConfig =>
    ({ ...extras, ...(config || {}) } as AxiosRequestConfig);

export const cartService = {
    getCart: (config?: AxiosRequestConfig): AxiosPromise =>
        api.get('/cart', withCartConfig(config, { skipAuthRedirect: true })),

    getSummary: (config?: AxiosRequestConfig): AxiosPromise =>
        api.get('/cart/summary', withCartConfig(config, { skipAuthRedirect: true, timeout: 20000 })),

    addItem: (data: CartItemData, config?: AxiosRequestConfig): AxiosPromise =>
        api.post('/cart/add', data, withCartConfig(config, { skipAuthRedirect: true, timeout: 6000 })),

    updateItem: (cartItemId: string | number, data: CartUpdateData, config?: AxiosRequestConfig): AxiosPromise =>
        api.put(`/cart/${cartItemId}`, data, withCartConfig(config, { skipAuthRedirect: true })),

    removeItem: (cartItemId: string | number, config?: AxiosRequestConfig): AxiosPromise =>
        api.delete(`/cart/${cartItemId}`, withCartConfig(config, { skipAuthRedirect: true })),

    clearCart: (config?: AxiosRequestConfig): AxiosPromise =>
        api.delete('/cart', withCartConfig(config, { skipAuthRedirect: true })),
};

export default cartService;