import api from './api';
import { AxiosRequestConfig, AxiosPromise } from 'axios';

interface LoginRequest {
    email: string;
    password: string;
}

interface RegisterRequest {
    email: string;
    password: string;
    name: string;
    [key: string]: unknown;
}

interface ForgotPasswordRequest {
    email: string;
}

interface ResetPasswordRequest {
    token: string;
    password: string;
}

interface AuthResponse {
    user: any;
    token: string;
}

interface SocialAuthUrlParams {
    provider: string;
    redirectTo: string;
}

export const authService = {
    register: (data: RegisterRequest | Record<string, unknown>): AxiosPromise => api.post('/auth/register', data),
    
    login: (data: LoginRequest, config?: AxiosRequestConfig): AxiosPromise => 
        api.post('/auth/login', data, { timeout: 12000, ...config }),
    
    forgotPassword: (data: ForgotPasswordRequest, config?: AxiosRequestConfig): AxiosPromise =>
        api.post(
            '/auth/forgot-password',
            {
                ...data,
                redirect_to: `${window.location.origin}/reset-password`,
            },
            { timeout: 8000, ...config }
        ),
    
    resetPassword: (data: ResetPasswordRequest, config?: AxiosRequestConfig): AxiosPromise => 
        api.post('/auth/reset-password', data, { timeout: 8000, ...config }),
    
    getSocialAuthUrl: (provider: string, redirectTo: string, config?: AxiosRequestConfig): AxiosPromise => 
        api.get(`/auth/oauth-url/${provider}`, { params: { redirect_to: redirectTo }, ...config }),
    
    logout: (config?: AxiosRequestConfig): AxiosPromise => 
        api.post('/auth/logout', {}, config),
    
    getProfile: (config?: AxiosRequestConfig): AxiosPromise => 
        api.get('/auth/me', { timeout: 3000, ...config }),
    
    updateProfile: (data: any, config?: AxiosRequestConfig): AxiosPromise => 
        api.put('/auth/profile', data, { timeout: 20000, ...config }),
    
    uploadAvatar: (file: File, config?: AxiosRequestConfig): AxiosPromise => {
        const formData = new FormData();
        formData.append('avatar', file);
        return api.post('/auth/profile/avatar', formData, {
            headers: {
                'Content-Type': 'multipart/form-data',
            },
            ...config,
        });
    },
};

export default authService;
