import api from './api';
import { AxiosRequestConfig, AxiosPromise } from 'axios';

interface ConcernPayload {
    subject: string;
    message: string;
    order_id?: string | number;
}

interface ConcernFiltersParams {
    status?: string;
    page?: number;
    per_page?: number;
    [key: string]: any;
}

const supportService = {
    submitConcern: (data: ConcernPayload, config?: AxiosRequestConfig): AxiosPromise => 
        api.post('/customer-concerns', data, config),
    
    getMyConcerns: (params?: ConcernFiltersParams, config?: AxiosRequestConfig): AxiosPromise => 
        api.get('/customer-concerns', { params, ...config }),
};

export default supportService;
