import { supabase } from '../supabaseClient';

type RecentOrder = {
  id: number;
  order_number: string | null;
  total_amount: number | string;
  status: string | null;
  created_at: string | null;
  user: { name?: string; email?: string } | null;
};

type LowStockProduct = {
  id: number;
  name: string;
  brand: string | null;
  stock: number;
};

export const getAdminAnalytics = async () => {
  const [usersRes, productsRes, ordersRes, revenueRes, recentOrdersRes, lowStockRes] = await Promise.all([
    supabase.from('users').select('id', { count: 'exact', head: true }),
    supabase.from('products').select('id', { count: 'exact', head: true }).eq('is_active', true),
    supabase.from('orders').select('id', { count: 'exact', head: true }),
    supabase.from('orders').select('total_amount').eq('payment_status', 'completed'),
    supabase
      .from('orders')
      .select('id,order_number,total_amount,status,created_at')
      .order('created_at', { ascending: false })
      .limit(8),
    supabase
      .from('products')
      .select('id,name,brand,stock')
      .lte('stock', 10)
      .order('stock', { ascending: true })
      .limit(8),
  ]);

  const firstError = [
    usersRes.error,
    productsRes.error,
    ordersRes.error,
    revenueRes.error,
    recentOrdersRes.error,
    lowStockRes.error,
  ].find(Boolean);

  if (firstError) {
    throw firstError;
  }

  const totalRevenue = (revenueRes.data || []).reduce((sum, row) => {
    return sum + Number((row as any).total_amount || 0);
  }, 0);

  const recentOrders: RecentOrder[] = (recentOrdersRes.data || []).map((row: any) => ({
    id: row.id,
    order_number: row.order_number,
    total_amount: row.total_amount,
    status: row.status,
    created_at: row.created_at,
    user: null,
  }));

  const lowStockProducts: LowStockProduct[] = (lowStockRes.data || []).map((row: any) => ({
    id: row.id,
    name: row.name,
    brand: row.brand,
    stock: Number(row.stock || 0),
  }));

  return {
    total_users: usersRes.count || 0,
    total_products: productsRes.count || 0,
    total_orders: ordersRes.count || 0,
    total_revenue: totalRevenue,
    recent_orders: recentOrders,
    low_stock_products: lowStockProducts,
  };
};
