import React, { useEffect, useState } from 'react';
import { Link, NavLink, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Header() {
    const { isAuthenticated, isAdmin, logout, logoutLoading } = useAuth();
    const location = useLocation();
    const navigate = useNavigate();
    const [searchQuery, setSearchQuery] = useState('');
    const [activeNav, setActiveNav] = useState('Home');
    const homePath = isAuthenticated ? (isAdmin ? '/admin/dashboard' : '/dashboard') : '/';
    const profilePath = isAdmin ? '/admin/account' : '/dashboard/profile';
    const ordersPath = isAdmin ? '/admin/orders' : '/dashboard/orders';

    useEffect(() => {
        if (location.pathname === '/' || location.pathname.startsWith('/dashboard')) {
            setActiveNav('Home');
            return;
        }

        if (location.pathname === '/orders' || location.pathname === '/dashboard/orders') {
            setActiveNav('My Orders');
        }
    }, [location.pathname]);

    const handleLogout = async () => {
        if (logoutLoading) {
            return;
        }

        if (!window.confirm('Are you sure you want to logout?')) {
            return;
        }

        try {
            await logout();
            navigate('/');
        } catch {
            navigate('/');
        }
    };

    const handleSearch = (e) => {
        e.preventDefault();
        if (searchQuery.trim()) {
            navigate(`/products?search=${encodeURIComponent(searchQuery)}`);
        }
    };

    const isSameRoute = (to) => {
        const [path, query = ''] = to.split('?');
        const targetSearch = query ? `?${query}` : '';
        return location.pathname === path && location.search === targetSearch;
    };

    const preventDuplicateNavigation = (to, event) => {
        if (isSameRoute(to)) {
            event.preventDefault();
        }
    };

    const navGroups = [
        {
            label: 'Shop',
            to: '/products',
            featured: { label: 'View all Shop items', to: '/products' },
            items: [
                { label: 'All Products', hint: 'Browse complete catalog', to: '/products' },
                { label: 'New Arrivals', hint: 'Latest added parts', to: '/products?sort_by=created_at&sort_order=desc' },
                { label: 'Top Rated', hint: 'Most trusted choices', to: '/products?search=best' },
                { label: 'Budget Picks', hint: 'Affordable quality parts', to: '/products?search=budget' }
            ]
        },
        {
            label: 'Brands',
            to: '/products',
            featured: { label: 'Explore all Brands', to: '/products' },
            items: [
                { label: 'Bosch', hint: 'German engineering', to: '/products?brand=bosch' },
                { label: 'Denso', hint: 'OEM trusted quality', to: '/products?brand=denso' },
                { label: 'NGK', hint: 'Spark and ignition experts', to: '/products?brand=ngk' },
                { label: 'ACDelco', hint: 'Reliable service parts', to: '/products?brand=acdelco' }
            ]
        },
        {
            label: 'Deals',
            to: '/products',
            isHot: true,
            featured: { label: 'Open all HOT deals', to: '/products?search=hot%20deal' },
            items: [
                { label: 'Flash Deals', hint: 'Limited-time offers', to: '/products?search=flash%20deal' },
                { label: 'Hot Deal Picks', hint: 'Best discounts right now', to: '/products?search=hot%20deal' },
                { label: 'Premium Parts', hint: 'Top-tier branded quality', to: '/products?search=premium' },
                { label: 'Premium Brake', hint: 'High-performance braking', to: '/products?search=premium%20brake' },
                { label: 'Premium Engine', hint: 'Long-life engine components', to: '/products?search=premium%20engine' },
                { label: 'Deal Accessories', hint: 'Great value add-ons', to: '/products?search=deal%20cover' }
            ],
            promo: {
                title: 'Deal Tip',
                text: 'Try Hot Deals and Premium filters to find the newest promo products fast.'
            }
        }
    ];

    return (
        <header className="site-header">
            <div className="header-top">
                <div className="header-inner">
                    <Link to={homePath} className="brand-logo" aria-label="CarVex home">
                        <span className="brand-mark">CV</span>
                        <div className="brand-details">
                            <span className="brand-name">CarVex</span>
                            <span className="brand-tagline">PREMIUM AUTO PARTS</span>
                        </div>
                    </Link>

                    <form className="search-form" onSubmit={handleSearch}>
                        <span className="search-icon" aria-hidden="true">
                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                <circle cx="11" cy="11" r="8" />
                                <path d="m21 21-4.35-4.35" />
                            </svg>
                        </span>
                        <input
                            type="text"
                            className="search-input"
                            placeholder="Search by part name, brand, or vehicle model..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                        {searchQuery && (
                            <button
                                type="button"
                                className="search-clear"
                                aria-label="Clear search"
                                onClick={() => setSearchQuery('')}
                            >
                                <span aria-hidden="true">x</span>
                            </button>
                        )}
                        <button type="submit" className="search-button">
                            Search
                        </button>
                    </form>

                    <div className="header-actions">
                        {isAuthenticated ? (
                            <div className="account-links">
                                <Link to={profilePath} className="action-link">
                                    <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
                                        <circle cx="12" cy="7" r="4" />
                                    </svg>
                                    <span>Profile</span>
                                </Link>
                                <Link to={ordersPath} className="action-link">
                                    <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <rect width="20" height="14" x="2" y="3" rx="2" />
                                        <line x1="8" x2="16" y1="21" y2="21" />
                                        <line x1="12" x2="12" y1="17" y2="21" />
                                    </svg>
                                    <span>Orders</span>
                                </Link>
                                {isAdmin && (
                                    <Link to="/admin/dashboard" className="action-link admin">
                                        <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                            <rect width="18" height="18" x="3" y="4" rx="2" ry="2" />
                                            <line x1="16" x2="16" y1="2" y2="6" />
                                            <line x1="8" x2="8" y1="2" y2="6" />
                                            <line x1="3" x2="21" y1="10" y2="10" />
                                        </svg>
                                        <span>Admin</span>
                                    </Link>
                                )}
                                <button
                                    type="button"
                                    className="action-link logout-btn"
                                    onClick={handleLogout}
                                    disabled={logoutLoading}
                                    aria-busy={logoutLoading}
                                >
                                    <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                        <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4" />
                                        <polyline points="16,17 21,12 16,7" />
                                        <line x1="21" x2="9" y1="12" y2="12" />
                                    </svg>
                                    <span>Logout</span>
                                </button>
                            </div>
                        ) : (
                            <Link to="/login" className="action-link">
                                <svg width="19" height="19" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                    <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
                                    <circle cx="12" cy="7" r="4" />
                                </svg>
                                <span>Login</span>
                            </Link>
                        )}


                    </div>
                </div>
            </div>

            <nav className="header-nav" aria-label="Primary">
                <div className="header-nav-inner">
                    <NavLink
                        to={homePath}
                        className={({ isActive }) => `nav-link ${isActive || activeNav === 'Home' ? 'active' : ''}`}
                        onClick={(event) => {
                            setActiveNav('Home');
                            preventDuplicateNavigation(homePath, event);
                        }}
                    >
                        Home
                    </NavLink>

                    {navGroups.map((group) => (
                        <div className="nav-item" key={group.label}>
                            <button
                                type="button"
                                className={`nav-link nav-trigger ${group.isHot ? 'hot-link' : ''} ${activeNav === group.label ? 'active' : ''}`}
                                onClick={() => setActiveNav(group.label)}
                            >
                                {group.isHot && <span className="hot-badge">HOT</span>}
                                {group.label}
                            </button>
                            <div className="nav-dropdown" role="menu" aria-label={`${group.label} links`}>
                                {group.items.map((item) => (
                                    <Link
                                        key={item.label}
                                        to={item.to}
                                        className="dropdown-link"
                                        role="menuitem"
                                        onClick={(event) => {
                                            setActiveNav(group.label);
                                            preventDuplicateNavigation(item.to, event);
                                        }}
                                    >
                                        <span className="dropdown-link-title">{item.label}</span>
                                        {item.hint && <span className="dropdown-link-hint">{item.hint}</span>}
                                    </Link>
                                ))}
                                {group.promo && (
                                    <div className="dropdown-promo">
                                        <span className="dropdown-promo-title">{group.promo.title}</span>
                                        <span className="dropdown-promo-text">{group.promo.text}</span>
                                    </div>
                                )}
                                <Link
                                    to={group.featured?.to || group.to}
                                    className="dropdown-featured-link"
                                    role="menuitem"
                                    onClick={(event) => {
                                        setActiveNav(group.label);
                                        preventDuplicateNavigation(group.featured?.to || group.to, event);
                                    }}
                                >
                                    <span>{group.featured?.label || `View ${group.label}`}</span>
                                    <span aria-hidden="true">{'->'}</span>
                                </Link>
                            </div>
                        </div>
                    ))}

                    {isAuthenticated && (
                        <NavLink
                            to={ordersPath}
                            className={({ isActive }) => `nav-link ${isActive || activeNav === 'My Orders' ? 'active' : ''}`}
                            onClick={(event) => {
                                setActiveNav('My Orders');
                                preventDuplicateNavigation(ordersPath, event);
                            }}
                        >
                            My Orders
                        </NavLink>
                    )}
                </div>
            </nav>
        </header>
    );
}
